import{_ as a,o as n,c as p,a3 as e}from"./chunks/framework.TOoDvHx0.js";const m=JSON.parse('{"title":"Autopilot","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/scenarios/autopilot.md","filePath":"pt-BR/scenarios/autopilot.md"}'),i={name:"pt-BR/scenarios/autopilot.md"};function l(o,s,t,r,c,d){return n(),p("div",null,[...s[0]||(s[0]=[e(`<h1 id="autopilot" tabindex="-1">Autopilot <a class="header-anchor" href="#autopilot" aria-label="Permalink to &quot;Autopilot&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Agentes: <code>@autopilot</code> · Complexidade: Média-Alta</p></div><p>Desenvolvimento autônomo iterativo usando um PRD como fonte da verdade e rastreamento de progresso entre iterações.</p><h2 id="mvp-overnight" tabindex="-1">MVP a partir de PRD (Build Noturno) <a class="header-anchor" href="#mvp-overnight" aria-label="Permalink to &quot;MVP a partir de PRD (Build Noturno) {#mvp-overnight}&quot;">​</a></h2><p><strong>Objetivo:</strong> Construir um MVP inteiro durante a noite, sem supervisão.</p><p><strong>Agentes envolvidos:</strong> <code>/prd</code> → <code>@autopilot</code> (10 iterações) → <code>/verify</code></p><h3 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Noite: Setup (15 min)</span></span>
<span class="line"><span>─────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: /prd App de gerenciamento de tarefas com Kanban, drag-and-drop e auth</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /prd gera:</span></span>
<span class="line"><span>  → docs/PRD-task-manager.md</span></span>
<span class="line"><span>  → 8 user stories com critérios de aceitação Gherkin</span></span>
<span class="line"><span>  → Decomposição em issues: 7 tasks (tamanho S-M)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Usuário revisa o PRD, ajusta se necessário.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: /autopilot docs/PRD-task-manager.md --max-iterations=10</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @autopilot inicializa:</span></span>
<span class="line"><span>  → Cria .claude/autopilot/progress.md</span></span>
<span class="line"><span>  → Extrai 7 tasks do PRD</span></span>
<span class="line"><span>  → Cria restore point no git</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Iteração 1: Modelos de dados</span></span>
<span class="line"><span>  → Cria schema Prisma (User, Board, Column, Task)</span></span>
<span class="line"><span>  → Roda prisma generate</span></span>
<span class="line"><span>  → ✓ DONE — comita, atualiza progress.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Iteração 2: Endpoints da API</span></span>
<span class="line"><span>  → Cria REST CRUD para boards, columns, tasks</span></span>
<span class="line"><span>  → Adiciona validação com Zod</span></span>
<span class="line"><span>  → Roda tsc --noEmit</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Iteração 3: Autenticação</span></span>
<span class="line"><span>  → Endpoints JWT login/register</span></span>
<span class="line"><span>  → Middleware de auth</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Iteração 4: Layout do frontend</span></span>
<span class="line"><span>  → Componente Kanban board</span></span>
<span class="line"><span>  → Componentes de coluna e card</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Iteração 5: Drag and drop</span></span>
<span class="line"><span>  → Integra dnd-kit / sortable</span></span>
<span class="line"><span>  → Atualiza posição da task via API</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Iteração 6: Dashboard do usuário</span></span>
<span class="line"><span>  → Lista de boards, fluxo de criação</span></span>
<span class="line"><span>  → Rotas protegidas</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Iteração 7: Testes</span></span>
<span class="line"><span>  → Testes unitários para serviços</span></span>
<span class="line"><span>  → Testes de integração para API</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Todas as tasks DONE → escreve AUTOPILOT_COMPLETE no progress.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Manhã seguinte: Usuário verifica progress.md e git log.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: /verify</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /verify confirma:</span></span>
<span class="line"><span>  → tsc: 0 erros</span></span>
<span class="line"><span>  → Testes: 24/24 passando</span></span>
<span class="line"><span>  → Build: sucesso</span></span></code></pre></div><hr><h2 id="db-migration" tabindex="-1">Migração de Banco de Dados (PostgreSQL para MySQL) <a class="header-anchor" href="#db-migration" aria-label="Permalink to &quot;Migração de Banco de Dados (PostgreSQL para MySQL) {#db-migration}&quot;">​</a></h2><p><strong>Objetivo:</strong> Migrar um projeto existente de PostgreSQL para MySQL.</p><p><strong>Comando:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/autopilot docs/PRD-db-migration.md --max-iterations=15 --model=claude-opus-4-6</span></span></code></pre></div><p><strong>O que acontece:</strong></p><ol><li><code>@autopilot</code> lê o PRD com os requisitos da migração</li><li>Cada iteração trata de uma task:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Iteração 1: Atualizar provider do Prisma</span></span>
<span class="line"><span>  → Muda provider de &quot;postgresql&quot; para &quot;mysql&quot;</span></span>
<span class="line"><span>  → Ajusta tipos de dados (TEXT → LONGTEXT, JSONB → JSON)</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Iteração 2: Corrigir incompatibilidades do schema</span></span>
<span class="line"><span>  → Arrays do PostgreSQL → colunas JSON</span></span>
<span class="line"><span>  → Diferenças no tratamento de enums</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Iteração 3: Atualizar scripts de seed</span></span>
<span class="line"><span>  → Ajusta sintaxe SQL para MySQL</span></span>
<span class="line"><span>  → Mudanças no formato de data</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Iteração 4: Atualizar queries</span></span>
<span class="line"><span>  → Substitui operadores específicos do PostgreSQL</span></span>
<span class="line"><span>  → ILIKE → LOWER() + LIKE</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Iteração 5: Atualizar Docker Compose</span></span>
<span class="line"><span>  → Substitui imagem postgres por mysql</span></span>
<span class="line"><span>  → Atualiza env vars (DATABASE_URL)</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Iteração 6: Rodar e corrigir testes</span></span>
<span class="line"><span>  → Corrige 3 testes falhando (comparação de datas)</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Iteração 7: Teste de integração</span></span>
<span class="line"><span>  → CRUD completo contra MySQL</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Todas as tasks DONE → AUTOPILOT_COMPLETE</span></span></code></pre></div><hr><h2 id="devcontainer" tabindex="-1">Feature com Script Mode (DevContainer) <a class="header-anchor" href="#devcontainer" aria-label="Permalink to &quot;Feature com Script Mode (DevContainer) {#devcontainer}&quot;">​</a></h2><p><strong>Objetivo:</strong> Construir um sistema de notificações usando script mode para máxima qualidade.</p><p><strong>Agentes envolvidos:</strong> <code>/prd</code> → <code>scripts/autopilot.sh</code> (em DevContainer)</p><h3 id="workflow-1" tabindex="-1">Workflow <a class="header-anchor" href="#workflow-1" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Setup: DevContainer (5 min)</span></span>
<span class="line"><span>───────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Copiar config do devcontainer</span></span>
<span class="line"><span>cp templates/autopilot/devcontainer.json .devcontainer/devcontainer.json</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Abrir no VS Code → &quot;Reopen in Container&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># No terminal do container:</span></span>
<span class="line"><span>claude</span></span>
<span class="line"><span>&gt; /prd Sistema de notificações em tempo real com WebSocket, in-app e email</span></span>
<span class="line"><span>&gt; exit</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Rodar autopilot (script mode — reset total de contexto)</span></span>
<span class="line"><span>./scripts/autopilot.sh docs/PRD-notifications.md \\</span></span>
<span class="line"><span>  --max-iterations=12 \\</span></span>
<span class="line"><span>  --model=claude-opus-4-6 \\</span></span>
<span class="line"><span>  --dangerously-skip-permissions</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Execução: Sem supervisão (2-3 horas)</span></span>
<span class="line"><span>─────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Cada iteração:</span></span>
<span class="line"><span>  1. Claude inicia do zero (contexto limpo)</span></span>
<span class="line"><span>  2. Lê PRD + progress.md</span></span>
<span class="line"><span>  3. Encontra próxima task PENDING</span></span>
<span class="line"><span>  4. Implementa completamente</span></span>
<span class="line"><span>  5. Atualiza progress.md</span></span>
<span class="line"><span>  6. Comita e sai</span></span>
<span class="line"><span>  7. Script mata o processo, inicia próxima iteração</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  === Autopilot: Iteração 1 de 12 ===</span></span>
<span class="line"><span>  Task: Setup do servidor WebSocket</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  === Autopilot: Iteração 2 de 12 ===</span></span>
<span class="line"><span>  Task: Modelos de dados de notificação</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  === Autopilot: Iteração 8 de 12 ===</span></span>
<span class="line"><span>  Task: Integração email (SendGrid)</span></span>
<span class="line"><span>  → BLOCKED (API key faltando no .env)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  === Autopilot: Iteração 9 de 12 ===</span></span>
<span class="line"><span>  Task: Sino de notificação no frontend</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Resultado: Verificar progresso</span></span>
<span class="line"><span>──────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>cat .claude/autopilot/progress.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Tasks: 9 DONE, 1 BLOCKED, 0 PENDING</span></span>
<span class="line"><span>  Iterações usadas: 11/12</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Corrigir task BLOCKED manualmente, depois continuar:</span></span>
<span class="line"><span>./scripts/autopilot.sh docs/PRD-notifications.md</span></span></code></pre></div><hr><h2 id="parallel-worktrees" tabindex="-1">Features Paralelas com Git Worktrees <a class="header-anchor" href="#parallel-worktrees" aria-label="Permalink to &quot;Features Paralelas com Git Worktrees {#parallel-worktrees}&quot;">​</a></h2><p><strong>Objetivo:</strong> Construir duas features independentes simultaneamente durante a noite.</p><h3 id="workflow-2" tabindex="-1">Workflow <a class="header-anchor" href="#workflow-2" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Setup: Criar worktrees</span></span>
<span class="line"><span>──────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>git worktree add ../project-auth -b feature/auth</span></span>
<span class="line"><span>git worktree add ../project-billing -b feature/billing</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Terminal 1:</span></span>
<span class="line"><span>cd ../project-auth</span></span>
<span class="line"><span>./scripts/autopilot.sh docs/PRD-auth.md \\</span></span>
<span class="line"><span>  --max-iterations=10 --dangerously-skip-permissions</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Terminal 2:</span></span>
<span class="line"><span>cd ../project-billing</span></span>
<span class="line"><span>./scripts/autopilot.sh docs/PRD-billing.md \\</span></span>
<span class="line"><span>  --max-iterations=10 --dangerously-skip-permissions</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Ambos rodam em paralelo, cada um com estado isolado</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Resultado: Manhã seguinte</span></span>
<span class="line"><span>─────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Verificar progresso de auth</span></span>
<span class="line"><span>cat ../project-auth/.claude/autopilot/progress.md</span></span>
<span class="line"><span>  → 6/6 tasks DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Verificar progresso de billing</span></span>
<span class="line"><span>cat ../project-billing/.claude/autopilot/progress.md</span></span>
<span class="line"><span>  → 7/8 tasks DONE, 1 BLOCKED</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Fazer merge dos resultados</span></span>
<span class="line"><span>cd ../project-auth &amp;&amp; git checkout main &amp;&amp; git merge feature/auth</span></span>
<span class="line"><span>cd ../project-billing &amp;&amp; git checkout main &amp;&amp; git merge feature/billing</span></span></code></pre></div><hr><h2 id="dicas-rapidas" tabindex="-1">Dicas Rápidas <a class="header-anchor" href="#dicas-rapidas" aria-label="Permalink to &quot;Dicas Rápidas&quot;">​</a></h2><h3 id="quando-usar-plugin-mode-vs-script-mode" tabindex="-1">Quando Usar Plugin Mode vs Script Mode <a class="header-anchor" href="#quando-usar-plugin-mode-vs-script-mode" aria-label="Permalink to &quot;Quando Usar Plugin Mode vs Script Mode&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plugin mode (/autopilot):</span></span>
<span class="line"><span>  ✓ Features rápidas (&lt; 5 tasks)</span></span>
<span class="line"><span>  ✓ Sessões acompanhadas</span></span>
<span class="line"><span>  ✓ Quando quer monitorar progresso ao vivo</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Script mode (scripts/autopilot.sh):</span></span>
<span class="line"><span>  ✓ Features complexas (10+ tasks)</span></span>
<span class="line"><span>  ✓ Execuções noturnas sem supervisão</span></span>
<span class="line"><span>  ✓ Migrações e refatorações grandes</span></span>
<span class="line"><span>  ✓ Quando qualidade degrada em sessões longas</span></span></code></pre></div><h3 id="escrevendo-bons-prds-para-autopilot" tabindex="-1">Escrevendo Bons PRDs para Autopilot <a class="header-anchor" href="#escrevendo-bons-prds-para-autopilot" aria-label="Permalink to &quot;Escrevendo Bons PRDs para Autopilot&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ FAÇA: Inclua critérios de aceitação claros por feature</span></span>
<span class="line"><span>✓ FAÇA: Quebre o trabalho em tasks pequenas e independentes</span></span>
<span class="line"><span>✓ FAÇA: Especifique requisitos de testes</span></span>
<span class="line"><span>✓ FAÇA: Defina a stack e padrões a seguir</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ NÃO: Deixe requisitos vagos (&quot;faça rápido&quot;)</span></span>
<span class="line"><span>✗ NÃO: Inclua decisões de design subjetivas</span></span>
<span class="line"><span>✗ NÃO: Combine features não relacionadas em um PRD</span></span>
<span class="line"><span>✗ NÃO: Pule a seção de decomposição em issues</span></span></code></pre></div><hr><h2 id="cenarios-relacionados" tabindex="-1">Cenários Relacionados <a class="header-anchor" href="#cenarios-relacionados" aria-label="Permalink to &quot;Cenários Relacionados&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-89/pt-BR/scenarios/planning.html">Planejamento</a> - Criar o plano antes do autopilot</li><li><a href="/pr-preview/pr-89/pt-BR/scenarios/workflows.html">Workflows</a> - Coordenação manual multi-agente</li><li><a href="/pr-preview/pr-89/pt-BR/scenarios/migration.html">Migração</a> - Cenários específicos de migração</li></ul>`,36)])])}const g=a(i,[["render",l]]);export{m as __pageData,g as default};
